      sessionStartedRef.current = true;
      setJourneyProgress(recordInitialSessionStart(backend));
    }
  }, [rosterQuery.isError, rosterQuery.isPending]);

  useEffect(() => {
    setEditorMarkdown(editor, notesMarkdown);
