      markChecklist("safe_first_task", {
        stage: "safe_first_task",
        milestone: "inventory_reviewed",
        route: canonicalJourneyUrl("/journeys/operator-access-admin/safe-task"),
        properties: {
          task: "inventory_review",
        },
