      });
      await Promise.all([
        queryClient.invalidateQueries({ queryKey: queryKeys.operatorRoster() }),
        queryClient.invalidateQueries({ queryKey: queryKeys.operatorInventoryRoot() }),
      ]);
    },
    onError: (error) => {
      setActionResult({
        title: "Operator notes update result",
        kind: "error",
        error: getErrorMessage(error),
        updatedAt: Date.now(),
      });
